15: func TestNewResourceDefault(t *testing.T) {
16: 	tests := []struct {
17: 		name string
18: 		envs map[string]string
19: 		want []attribute.KeyValue
20: 	}{
21: 		{
22: 			name: "with envs",
23: 			envs: map[string]string{
24: 				"OTEL_SERVICE_NAME":        "myservice",
25: 				"OTEL_RESOURCE_ATTRIBUTES": "key1=value1",
26: 			},
27: 			want: []attribute.KeyValue{
28: 				attribute.Key("key1").String("value1"),
29: 				semconv.ServiceName("myservice"),
30: 				semconv.ServiceVersion("test"),
31: 			},
32: 		},
33: 		{
34: 			name: "default",
35: 			envs: map[string]string{},
36: 			want: []attribute.KeyValue{
37: 				semconv.ServiceName("flipt"),
38: 				semconv.ServiceVersion("test"),
39: 			},
40: 		},
41: 	}
42: 	for _, tt := range tests {
43: 		t.Run(tt.name, func(t *testing.T) {
44: 			for k, v := range tt.envs {
45: 				t.Setenv(k, v)
46: 			}
47: 			r, err := newResource(context.Background(), "test")
48: 			assert.NoError(t, err)
49: 
50: 			want := make(map[attribute.Key]attribute.KeyValue)
51: 			for _, keyValue := range tt.want {
52: 				want[keyValue.Key] = keyValue
53: 			}
54: 
55: 			for _, keyValue := range r.Attributes() {
56: 				if wantKeyValue, ok := want[keyValue.Key]; ok {
57: 					assert.Equal(t, wantKeyValue, keyValue)
58: 				}
59: 			}
60: 		})
61: 	}
62: }
