	if checker != nil {
		tokenDeletedEnabled = checker.Check("token:deleted")
	}

	register, authInterceptors, authShutdown, err := authenticationGRPC(
		ctx,
		logger,
		cfg,
		forceMigrate,
		tokenDeletedEnabled,
		authOpts...,
	)
